const item = $input.first().json;
const statusCode = item.status || 0;
const responseTime = item.responseTime || 0;
const timestamp = new Date().toISOString();
const isUp = statusCode === 200;

return [{
  json: {
    url: 'https://demo.realworld.show',
    statusCode,
    responseTime: Math.round(responseTime),
    isUp,
    timestamp,
    alertMessage: isUp 
      ? `UP: Conduit returned ${statusCode} in ${Math.round(responseTime)}ms`
      : `DOWN: Conduit returned ${statusCode} (expected 200). Response time: ${Math.round(responseTime)}ms`
  }
}];

const originalItem = $('Check Status').first().json;
const retryItem = $input.first().json;
const retryStatus = retryItem.status || 0;
const isStillDown = retryStatus !== 200;

return [{
  json: {
    ...originalItem,
    retryStatus,
    isStillDown,
    finalMessage: isStillDown
      ? `CONFIRMED DOWN: Conduit failed both attempts. First: ${originalItem.statusCode}, Retry: ${retryStatus}. Response time: ${originalItem.responseTime}ms. Time: ${originalItem.timestamp}`
      : `RECOVERED: Conduit was down on first check (${originalItem.statusCode}) but recovered on retry (${retryStatus}). Time: ${originalItem.timestamp}`
  }
}];

// Log all checks (both up and down) for daily summary
const item = $('Check Status').first().json;

// Store in workflow static data for daily summary
const staticData = $getWorkflowStaticData('global');
if (!staticData.checks) {
  staticData.checks = [];
}

staticData.checks.push({
  timestamp: item.timestamp,
  isUp: item.isUp,
  statusCode: item.statusCode,
  responseTime: item.responseTime
});

// Keep only last 288 checks (24 hours at 5-min intervals)
if (staticData.checks.length > 288) {
  staticData.checks = staticData.checks.slice(-288);
}

return [{ json: { logged: true, totalChecks: staticData.checks.length } }];

const staticData = $getWorkflowStaticData('global');
const checks = staticData.checks || [];

if (checks.length === 0) {
  return [{ json: { message: 'No checks recorded in the last 24 hours.' } }];
}

const totalChecks = checks.length;
const upChecks = checks.filter(c => c.isUp).length;
const downChecks = totalChecks - upChecks;
const uptimePercent = ((upChecks / totalChecks) * 100).toFixed(2);
const avgResponseTime = Math.round(checks.reduce((sum, c) => sum + c.responseTime, 0) / totalChecks);
const maxResponseTime = Math.max(...checks.map(c => c.responseTime));
const minResponseTime = Math.min(...checks.map(c => c.responseTime));

const downtimeEvents = checks.filter(c => !c.isUp);
const lastDowntime = downtimeEvents.length > 0 
  ? downtimeEvents[downtimeEvents.length - 1].timestamp 
  : 'None';

const summary = `Daily Uptime Summary - Conduit Demo
` +
  `Period: Last ${totalChecks} checks (~${Math.round(totalChecks * 5 / 60)} hours)

` +
  `Uptime: ${uptimePercent}%
` +
  `Total Checks: ${totalChecks}
` +
  `Up: ${upChecks} | Down: ${downChecks}

` +
  `Response Time (ms):
` +
  `  Average: ${avgResponseTime}ms
` +
  `  Min: ${minResponseTime}ms
` +
  `  Max: ${maxResponseTime}ms

` +
  `Last Downtime: ${lastDowntime}`;

// Clear static data for next day
staticData.checks = [];

return [{ json: { summary, uptimePercent: parseFloat(uptimePercent), totalChecks, upChecks, downChecks, avgResponseTime } }];
